const LOCAL_CONSOLE_AGENT_ID: &str = "local-console";

fn timestamp_ms_to_rfc3339(timestamp_ms: u64) -> Option<String> {
    chrono::DateTime::<chrono::Utc>::from_timestamp_millis(timestamp_ms as i64)
        .map(|timestamp| timestamp.to_rfc3339())
}

fn local_console_identity(state: &AppState) -> AgentIdentity {
    let now = chrono::Utc::now().to_rfc3339();
    let enrolled_at = state
        .local_telemetry
        .front()
        .and_then(|sample| timestamp_ms_to_rfc3339(sample.timestamp_ms))
        .unwrap_or_else(|| now.clone());
    let last_seen = state
        .local_telemetry
        .back()
        .and_then(|sample| timestamp_ms_to_rfc3339(sample.timestamp_ms))
        .unwrap_or_else(|| now.clone());
    let mut labels = HashMap::new();
    labels.insert("local_console".to_string(), "true".to_string());
    labels.insert("role".to_string(), "control-plane".to_string());

    AgentIdentity {
        id: LOCAL_CONSOLE_AGENT_ID.to_string(),
        hostname: state.local_host_info.hostname.clone(),
        platform: state.local_host_info.platform.to_string(),
        version: env!("CARGO_PKG_VERSION").to_string(),
        enrolled_at,
        last_seen,
        status: AgentStatus::Online,
        labels,
        health: AgentHealth {
            pending_alerts: state
                .alerts
                .iter()
                .filter(|alert| alert.hostname == state.local_host_info.hostname)
                .count(),
            telemetry_queue_depth: state.local_telemetry.len(),
            ..AgentHealth::default()
        },
        monitor_scope: None,
    }
}

fn local_console_agent_summary_json(state: &AppState) -> serde_json::Value {
    let local_agent = local_console_identity(state);
    let latest_sample = state.local_telemetry.back();
    let mut summary = agent_summary_json(
        &local_agent,
        None,
        state.agent_registry.heartbeat_interval(),
    );
    if let Some(object) = summary.as_object_mut() {
        object.insert("local_console".to_string(), serde_json::Value::Bool(true));
        object.insert(
            "local_monitoring".to_string(),
            serde_json::Value::Bool(true),
        );
        object.insert(
            "source".to_string(),
            serde_json::Value::String("local".to_string()),
        );
        object.insert(
            "os_version".to_string(),
            serde_json::Value::String(state.local_host_info.os_version.clone()),
        );
        object.insert(
            "arch".to_string(),
            serde_json::Value::String(state.local_host_info.arch.clone()),
        );
        object.insert(
            "telemetry_samples".to_string(),
            serde_json::Value::Number(serde_json::Number::from(state.local_telemetry.len())),
        );
        object.insert(
            "process_count".to_string(),
            serde_json::json!(latest_sample.map(|sample| sample.process_count)),
        );
        object.insert(
            "inventory_available".to_string(),
            serde_json::Value::Bool(state.last_inventory.is_some()),
        );
    }
    summary
}

pub async fn run_server(
    port: u16,
    site_dir: &Path,
    shutdown: Arc<AtomicBool>,
    initial_config: Config,
) -> Result<(), String> {
    let addr = format!("0.0.0.0:{port}");

    // Determine TLS mode from environment variables
    let tls_cert = std::env::var("WARDEX_TLS_CERT").ok();
    let tls_key = std::env::var("WARDEX_TLS_KEY").ok();

    if let (Some(cert_path), Some(key_path)) = (&tls_cert, &tls_key) {
        // Validate that cert/key files exist and are readable at startup
        if !std::path::Path::new(cert_path).exists() {
            return Err(format!("WARDEX_TLS_CERT file not found: {cert_path}"));
        }
        if !std::path::Path::new(key_path).exists() {
            return Err(format!("WARDEX_TLS_KEY file not found: {key_path}"));
        }
        // Validate PEM structure
        let cert_contents = std::fs::read_to_string(cert_path)
            .map_err(|e| format!("failed to read TLS cert {cert_path}: {e}"))?;
        let key_contents = std::fs::read_to_string(key_path)
            .map_err(|e| format!("failed to read TLS key {key_path}: {e}"))?;
        if !cert_contents.contains("-----BEGIN") {
            return Err(format!(
                "WARDEX_TLS_CERT does not appear to be valid PEM: {cert_path}"
            ));
        }
        if !key_contents.contains("-----BEGIN") {
            return Err(format!(
                "WARDEX_TLS_KEY does not appear to be valid PEM: {key_path}"
            ));
        }
        eprintln!(
            "  NOTE: TLS configured via WARDEX_TLS_CERT/KEY — use a reverse proxy (nginx/caddy) for production TLS"
        );
    } else if tls_cert.is_some() || tls_key.is_some() {
        return Err(
            "Both WARDEX_TLS_CERT and WARDEX_TLS_KEY must be set (only one was provided)".into(),
        );
    }

    let listener = tokio::net::TcpListener::bind(&addr)
        .await
        .map_err(|e| format!("failed to bind {addr}: {e}"))?;

    let config_path = crate::config::runtime_config_path();

    // Use persistent token from environment if set, otherwise generate a random one
    let token = std::env::var("WARDEX_ADMIN_TOKEN").unwrap_or_else(|_| generate_token());
    let scheme = if tls_cert.is_some() && tls_key.is_some() && cfg!(feature = "tls") {
        "https"
    } else {
        "http"
    };
    eprintln!("Wardex admin console");
    eprintln!("  Listening on {scheme}://localhost:{port}");
    eprintln!("  Site directory: {}", site_dir.display());
    if std::env::var("WARDEX_ADMIN_TOKEN").is_ok() {
        eprintln!("  Auth token: (set via WARDEX_ADMIN_TOKEN)");
    } else {
        // Write generated token to a secure file instead of printing to stderr
        let token_path = std::path::Path::new("var").join(".wardex_token");
        if let Ok(()) = std::fs::create_dir_all("var") {
            if let Ok(()) = std::fs::write(&token_path, &token) {
                #[cfg(unix)]
                {
                    use std::os::unix::fs::PermissionsExt;
                    let _ = std::fs::set_permissions(
                        &token_path,
                        std::fs::Permissions::from_mode(0o600),
                    );
                }
                eprintln!(
                    "  Auth token: written to {} (mode 0600)",
                    token_path.display()
                );
            } else {
                eprintln!("  Auth token: {token}");
            }
        } else {
            eprintln!("  Auth token: {token}");
        }
        eprintln!("  (set WARDEX_ADMIN_TOKEN env var for a persistent token)");
    }
    eprintln!("  Press Ctrl+C to stop");

    // Derive spool encryption key from env var; in production mode, require it explicitly
    let is_production = std::env::var("WARDEX_ENV")
        .map(|v| v.eq_ignore_ascii_case("production"))
        .unwrap_or(false);
    let spool_key = match std::env::var("WARDEX_SPOOL_KEY") {
        Ok(k) => sha2::Sha256::digest(k.as_bytes()),
        Err(_) if is_production => {
            return Err("WARDEX_SPOOL_KEY must be set when WARDEX_ENV=production. \
                 Set it to a persistent secret to ensure spool data survives token rotation."
                .into());
        }
        Err(_) => {
            eprintln!("  WARNING: WARDEX_SPOOL_KEY not set — spool key derived from admin token.");
            eprintln!("           Rotating the token will make existing spool data unreadable.");
            eprintln!("           Set WARDEX_SPOOL_KEY to a persistent secret for production use.");
            sha2::Sha256::digest(format!("spool-key-{token}").as_bytes())
        }
    };
    let session_store = crate::auth::SessionStore::with_persistence_key(
        &session_store_path(&config_path),
        Some(load_or_create_session_seal_key(&config_path)),
    );
    let user_preferences = UserPreferencesStore::new(&user_preferences_store_path(&config_path));
    let model_registry_dir = model_registry_path(&config_path);
    let detection_feedback_path = detection_feedback_store_path(&config_path);

    let state = Arc::new(Mutex::new(AppState {
        detector: AnomalyDetector::default(),
        checkpoints: CheckpointStore::new(10),
        device: DeviceController::default(),
        replay: ReplayBuffer::new(200),
        proofs: ProofRegistry::new(),
        last_report: None,
        last_failover_drill: None,
        token: token.clone(),
        token_issued_at: std::time::Instant::now(),
        session_store,
        oidc_providers: HashMap::new(),
        user_preferences,
        swarm: SwarmNode::new("gateway-0"),
        cluster: ClusterNode::new(initial_config.cluster.clone()),
        enforcement: EnforcementEngine::new(),
        threat_intel: ThreatIntelStore::new(),
        digital_twin: DigitalTwinEngine::new(),
        compliance: ComplianceManager::new(),
        multi_tenant: MultiTenantManager::new(),
        energy: EnergyBudget::new(500.0),
        side_channel: SideChannelDetector::new(),
        key_rotation: KeyRotationManager::new(3600),
        privacy: PrivacyAccountant::new(10.0),
        policy_vm: PolicyVm::default(),
        fingerprint: None,
        monitor: Monitor::new(),
        drift: DriftDetector::new(0.005, 50.0),
        deception: DeceptionEngine::new(),
        patches: PatchManager::new(),
        causal: CausalGraph::new(),
        listener_mode: if tls_cert.is_some() && tls_key.is_some() && cfg!(feature = "tls") {
            ListenerMode::Tls {
                port,
                config: crate::tls::TlsConfig::new(
                    tls_cert.as_deref().unwrap_or_default(),
                    tls_key.as_deref().unwrap_or_default(),
                ),
            }
        } else {
            ListenerMode::Plain { port }
        },
        config: Config::default(),
        config_path,
        alerts: VecDeque::new(),
        server_start: std::time::Instant::now(),
        agent_registry: AgentRegistry::new("var/agents.json"),
        event_store: EventStore::with_persistence(10_000, "var/events.json"),
        clickhouse_store: initial_config.clickhouse.as_ref().map(|cfg| {
            log::info!(
                "[STORAGE] ClickHouse backend enabled: {}/{}",
                cfg.url,
                cfg.database
            );
            crate::storage_clickhouse::ClickHouseStorage::new(cfg.clone())
        }),
        policy_store: PolicyStore::new(),
        update_manager: UpdateManager::new("var/updates"),
        remote_deployments: load_remote_deployments("var/deployments.json"),
        deployment_store_path: "var/deployments.json".to_string(),
        siem_connector: SiemConnector::new(initial_config.siem.clone()),
        taxii_client: crate::siem::TaxiiClient::new(initial_config.taxii.clone()),
        local_telemetry: VecDeque::new(),
        local_host_info: detect_platform(),
        last_inventory: None,
        last_inventory_at_ms: 0,
        velocity: VelocityDetector::new(60, 2.5),
        entropy: EntropyDetector::new(60, 8),
        compound: CompoundThreatDetector::default(),
        shutdown: shutdown.clone(),
        rate_limiter: RateLimiter::new(
            initial_config.server.rate_limit_read_per_minute,
            initial_config.server.rate_limit_write_per_minute,
        ),
        audit_log: AuditLog::new(1000),
        incident_store: IncidentStore::new("var/incidents.json"),
        agent_logs: HashMap::new(),
        agent_logs_last_access: HashMap::new(),
        agent_inventories: HashMap::new(),
        report_store: crate::report::ReportStore::new("var/reports.json"),
        support_store: SupportStore::new("var/support.json"),
        sigma_engine: SigmaEngine::new(),
        response_orchestrator: ResponseOrchestrator::new(),
        feature_flags: FeatureFlagRegistry::new(),
        process_tree: ProcessTree::new("localhost"),
        spool: EncryptedSpool::try_new(&spool_key, 10_000)
            .map_err(|err| format!("failed to initialise encrypted spool: {err}"))?,
        rbac: RbacStore::new(),
        case_store: CaseStore::new("var/cases.json"),
        alert_queue: AlertQueue::new(),
        approval_log: ApprovalLog::new(),
        dead_letter_queue: DeadLetterQueue::new(500),
        enterprise: EnterpriseStore::new("var/enterprise.json"),
        request_count: 0,
        error_count: 0,
        beacon_detector: crate::beacon::BeaconDetector::default(),
        ueba_engine: crate::ueba::UebaEngine::default(),
        kill_chain_analyzer: crate::kill_chain::KillChainAnalyzer::new(),
        lateral_detector: crate::lateral::LateralMovementDetector::default(),
        playbook_engine: crate::playbook::PlaybookEngine::new(),
        live_response_engine: crate::live_response::LiveResponseEngine::default(),
        remediation_engine: crate::remediation::RemediationEngine::new(),
        escalation_engine: crate::escalation::EscalationEngine::new(),
        kernel_event_stream: crate::kernel_events::KernelEventStream::new(10_000),
        last_alert_analysis: None,
        storage: SharedStorage::open("var/storage")
            .or_else(|_| SharedStorage::open("/tmp/wardex_storage"))
            .map_err(|e| format!("failed to initialise storage: {e}"))?,
        slow_attack: crate::detector::SlowAttackDetector::default(),
        ransomware: crate::ransomware::RansomwareDetector::default(),
        mitre_coverage: crate::mitre_coverage::MitreCoverageTracker::new(),
        tuning_profile: crate::detector::TuningProfile::default(),
        fp_feedback: crate::alert_analysis::FpFeedbackStore::new(),
        vulnerability_scanner: crate::vulnerability::VulnerabilityScanner::new(),
        ndr_engine: crate::ndr::NdrEngine::new(crate::ndr::NdrConfig::default()),
        container_detector: crate::container::ContainerDetector::new(),
        cert_monitor: crate::cert_monitor::CertMonitor::new(),
        config_drift_detector: crate::config_drift::ConfigDriftDetector::new(),
        asset_inventory: crate::cloud_inventory::AssetInventory::new(),
        efficacy_tracker: crate::detection_efficacy::EfficacyTracker::new(100_000),
        workflow_store: crate::investigation::WorkflowStore::new(),
        llm_analyst: Arc::new(Mutex::new(load_llm_analyst_from_env())),
        model_registry: crate::ml_engine::ModelRegistry::new(&model_registry_dir),
        detection_feedback: crate::detection_feedback::DetectionFeedbackStore::new(
            &detection_feedback_path,
        ),
        malware_hash_db: crate::malware_signatures::MalwareHashDb::new(),
        malware_scanner: crate::malware_scanner::MalwareScanner::new(),
        yara_engine: crate::yara_engine::YaraEngine::new(),
        api_analytics: crate::api_analytics::ApiAnalytics::new(),
        trace_collector: crate::telemetry::TraceCollector::new(10000),
        feed_engine: crate::feed_ingestion::FeedIngestionEngine::new_with_defaults(),
        playbook_dsl: crate::playbook_dsl::PlaybookDslStore::new(),
        image_inventory: crate::container_image::ImageInventory::new(),
        quarantine_store: crate::quarantine::QuarantineStore::new(),
        lifecycle_manager: crate::agent_lifecycle::LifecycleManager::new(
            crate::agent_lifecycle::LifecycleConfig::default(),
        ),
        decay_config: crate::ioc_decay::DecayConfig::default(),
        dns_analyzer: crate::dns_threat::DnsAnalyzer::new(),
        alert_broadcaster: crate::ws_stream::AlertBroadcaster::new(),
        extra: HashMap::new(),
    }));

    // Apply loaded config
    let shutdown_timeout_secs = initial_config.server.shutdown_timeout_secs;

    {
        let mut s = state.lock().unwrap_or_else(|e| e.into_inner());
        s.config = initial_config;
        let effective_rules = s.enterprise.effective_sigma_rules();
        s.sigma_engine.replace_rules(effective_rules);
    }

    // Load community YARA malware rules
    {
        let yara_path = std::path::Path::new("rules/yara/malware.json");
        if yara_path.exists()
            && let Ok(json) = std::fs::read_to_string(yara_path)
        {
            let mut s = state.lock().unwrap_or_else(|e| e.into_inner());
            match s.yara_engine.load_rules_json(&json) {
                Ok(n) => tracing::info!("loaded {n} community YARA malware rules"),
                Err(e) => tracing::warn!("failed to load YARA malware rules: {e}"),
            }
        }
    }

    spawn_enterprise_hunt_scheduler(&state);
    spawn_retention_purge_scheduler(&state);
    spawn_cluster_runtime_loop(&state);

    // ── Spawn local host monitoring thread ──────────────────────────
    {
        let monitor_state = Arc::clone(&state);
        std::thread::spawn(move || {
            let mut cs = CollectorState::default();
            let mut consecutive_elevated: u32 = 0;
            let mut file_watch_cache: Vec<String> = Vec::new();
            let mut file_monitor: Option<FileIntegrityMonitor> = None;
            let mut persistence_watch_cache: Vec<String> = Vec::new();
            let mut persistence_monitor: Option<FileIntegrityMonitor> = None;
            const CONFIRM_SAMPLES: u32 = 2; // require N consecutive elevated before alerting
            loop {
                let (scope, watch_paths, host_platform) = {
                    let s = monitor_state.lock().unwrap_or_else(|e| e.into_inner());
                    (
                        s.config.monitor.scope.clone(),
                        s.config.monitor.watch_paths.clone(),
                        s.local_host_info.platform,
                    )
                };

                if scope.file_integrity {
                    if watch_paths != file_watch_cache {
                        file_monitor = if watch_paths.is_empty() {
                            None
                        } else {
                            Some(FileIntegrityMonitor::new(&watch_paths))
                        };
                        file_watch_cache = watch_paths.clone();
                    }
                } else {
                    file_monitor = None;
                    file_watch_cache.clear();
                }

                let persistence_paths =
                    crate::collector::persistence_watch_paths(host_platform, &scope);
                if persistence_paths != persistence_watch_cache {
                    persistence_monitor = if persistence_paths.is_empty() {
                        None
                    } else {
                        Some(FileIntegrityMonitor::new(&persistence_paths))
                    };
                    persistence_watch_cache = persistence_paths;
                }

                let sample = crate::collector::collect_sample_scoped(
                    &mut cs,
                    file_monitor.as_ref(),
                    persistence_monitor.as_ref(),
                    &scope,
                );
                {
                    let mut s = match monitor_state.lock() {
                        Ok(g) => g,
                        Err(e) => e.into_inner(),
                    };
                    if s.local_telemetry.len() >= 300 {
                        s.local_telemetry.pop_front();
                    }
                    s.local_telemetry.push_back(sample);
                    // Refresh host inventory (top processes + sockets) at most
                    // once every 10 s. Best-effort: failure leaves the last
                    // snapshot in place.
                    let should_refresh_inventory =
                        sample.timestamp_ms.saturating_sub(s.last_inventory_at_ms) > 10_000;
                    if should_refresh_inventory {
                        let inventory = crate::collector::collect_host_inventory(50, 50);
                        s.last_inventory_at_ms = sample.timestamp_ms;
                        s.last_inventory = Some(inventory);
                    }
                    let mut signal = s.detector.evaluate(&sample);

                    // Phase 21: velocity / entropy / compound enrichment
                    let vel_report = s.velocity.update(&sample);
                    let ent_report = s.entropy.update(&sample);
                    signal.score += vel_report.score_boost + ent_report.score_boost;
                    let mut extra_reasons: Vec<String> = Vec::new();
                    for ax in &vel_report.anomalous_axes {
                        extra_reasons.push(format!("velocity-spike:{ax}"));
                    }
                    for ax in &ent_report.anomalous_axes {
                        extra_reasons.push(format!("entropy-anomaly:{ax}"));
                    }
                    let cmp_report = s.compound.evaluate(&signal);
                    if cmp_report.is_compound_attack {
                        signal.score = cmp_report.compound_score;
                        extra_reasons.push(format!(
                            "compound-threat({:.0}%)",
                            cmp_report.concurrent_fraction * 100.0
                        ));
                    }
                    signal.reasons.extend(extra_reasons);

                    let crit = s.config.policy.critical_score;
                    let sev = s.config.policy.severe_score;
                    let elev = s.config.policy.elevated_score;
                    if signal.score >= elev {
                        consecutive_elevated += 1;
                        // Critical/Severe bypass confirmation — alert immediately
                        // Elevated requires consecutive confirmation to suppress noise
                        let confirmed =
                            signal.score >= sev || consecutive_elevated >= CONFIRM_SAMPLES;
                        if confirmed {
                            let level = if signal.score >= crit {
                                "Critical"
                            } else if signal.score >= sev {
                                "Severe"
                            } else {
                                "Elevated"
                            };
                            let host = s.local_host_info.clone();
                            let mitre = crate::telemetry::map_alert_to_mitre(&signal.reasons);
                            let recent_samples: Vec<_> =
                                s.local_telemetry.iter().cloned().collect();
                            let mut alert = AlertRecord {
                                timestamp: chrono::Utc::now().to_rfc3339(),
                                hostname: host.hostname.clone(),
                                platform: host.platform.to_string(),
                                score: signal.score,
                                confidence: signal.confidence,
                                level: level.to_string(),
                                action: "monitor".to_string(),
                                reasons: signal.reasons,
                                sample,
                                enforced: false,
                                mitre,
                                narrative: None,
                            };
                            alert.narrative = Some(crate::collector::build_alert_narrative(
                                &alert,
                                &recent_samples,
                                s.last_inventory.as_ref(),
                            ));
                            if s.alerts.len() >= 10_000 {
                                s.alerts.pop_front();
                            }
                            s.alerts.push_back(alert.clone());
                            let process_catalog =
                                assemble_alert_process_catalog(&host.hostname, &s.process_tree);
                            let alert_event = alert_json_value(
                                &alert,
                                s.alerts.len().saturating_sub(1),
                                &host.hostname,
                                &process_catalog,
                            );
                            s.alert_broadcaster.broadcast_alert(alert_event);

                            // Phase 33: broadcast high-severity intel to swarm
                            if alert.score >= sev {
                                let swarm_id = s.swarm.id.clone();
                                for reason in &alert.reasons {
                                    if reason.contains("network burst")
                                        || reason.contains("velocity-spike")
                                    {
                                        let _msg = s.swarm.broadcast_threat_intel(
                                            crate::swarm::GossipPayload::ThreatIntelUpdate {
                                                ioc_type: "network_anomaly".into(),
                                                indicator: format!("{}:{}", alert.hostname, reason),
                                                confidence: alert.confidence,
                                                source_agent: swarm_id.clone(),
                                                ttl_hours: 24,
                                            },
                                        );
                                    }
                                }
                            }
                        }
                    } else {
                        consecutive_elevated = 0;
                    }
                    let interval = s.config.monitor.interval_secs.max(1);
                    drop(s);
                    std::thread::sleep(std::time::Duration::from_secs(interval));
                }
            }
        });
    }

    // ── Spawn background alert analysis thread (every 5 minutes) ────
    {
        let analysis_state = Arc::clone(&state);
        std::thread::spawn(move || {
            loop {
                std::thread::sleep(std::time::Duration::from_secs(300));
                {
                    let s = match analysis_state.lock() {
                        Ok(g) => g,
                        Err(e) => e.into_inner(),
                    };
                    if s.shutdown.load(Ordering::Relaxed) {
                        break;
                    }
                    let alerts_vec: Vec<_> = s.alerts.iter().cloned().collect();
                    drop(s);
                    let analysis = crate::alert_analysis::analyze_alerts(&alerts_vec, 5);
                    let mut s = match analysis_state.lock() {
                        Ok(g) => g,
                        Err(e) => e.into_inner(),
                    };
                    s.last_alert_analysis = Some(analysis);
                }
            }
        });
    }

    let site_dir = site_dir.to_path_buf();

    // Build axum router
    let shared_state = Arc::clone(&state);
    let shared_site = site_dir.clone();

    // Use a Notify channel for immediate shutdown signaling instead of polling
    let shutdown_notify = Arc::new(tokio::sync::Notify::new());
    let shutdown_notify_bg = shutdown_notify.clone();
    let shutdown_flag_check = shutdown.clone();
    tokio::spawn(async move {
        loop {
            tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
            if shutdown_flag_check.load(Ordering::Relaxed) {
                shutdown_notify_bg.notify_waiters();
                break;
            }
        }
    });

    use axum::Router;
    use axum::extract::ConnectInfo;
    let app = Router::new().fallback(
        move |method: HttpMethod,
              uri: axum::http::Uri,
              headers: HeaderMap,
              ConnectInfo(addr): ConnectInfo<std::net::SocketAddr>,
              body: axum::body::Bytes| {
            let state = shared_state.clone();
            let site_dir = shared_site.clone();
            async move {
                let url = uri.to_string();
                let remote_addr = addr.ip().to_string();

                // Rate limiting
                {
                    let method_compat = Method::from_http(&method);
                    let mut s = match state.lock() {
                        Ok(g) => g,
                        Err(e) => e.into_inner(),
                    };
                    s.request_count += 1;
                    if !s.rate_limiter.check(&remote_addr, &method_compat, &url) {
                        drop(s);
                        if url.starts_with("/api/") {
                            return respond_api(
                                &state,
                                &method_compat,
                                &url,
                                &remote_addr,
                                false,
                                error_json("rate limit exceeded", 429),
                            );
                        } else {
                            return error_json("rate limit exceeded", 429);
                        }
                    }
                }

                // CORS preflight
                if method == HttpMethod::OPTIONS {
                    let origin = cors_origin();
                    return Response::builder()
                        .status(204)
                        .header("Access-Control-Allow-Origin", origin)
                        .header(
                            "Access-Control-Allow-Methods",
                            "GET, POST, PUT, DELETE, PATCH, OPTIONS",
                        )
                        .header(
                            "Access-Control-Allow-Headers",
                            "Content-Type, Authorization",
                        )
                        .header("Access-Control-Max-Age", "86400")
                        .body(Body::empty())
                        .unwrap_or_else(|_| Response::new(Body::empty()));
                }

                if url.starts_with("/api/") {
                    let m = Method::from_http(&method);
                    let hdrs = headers.clone();
                    let body_bytes: Vec<u8> = body.to_vec();
                    let st = state.clone();
                    let u = url.clone();
                    let ra = remote_addr.clone();
                    match tokio::task::spawn_blocking(move || {
                        // Catch panics so one bad request cannot crash the server
                        std::panic::catch_unwind(std::panic::AssertUnwindSafe(move || {
                            handle_api(m, &u, &hdrs, &body_bytes, &ra, &st)
                        }))
                    })
                    .await
                    {
                        Ok(Ok(resp)) => resp,
                        Ok(Err(panic_info)) => {
                            let msg = if let Some(s) = panic_info.downcast_ref::<&str>() {
                                s.to_string()
                            } else if let Some(s) = panic_info.downcast_ref::<String>() {
                                s.clone()
                            } else {
                                "unknown panic in request handler".to_string()
                            };
                            log::error!("[PANIC-RECOVERED] request handler panic: {msg}");
                            let mut s = match state.lock() {
                                Ok(g) => g,
                                Err(e) => e.into_inner(),
                            };
                            s.error_count += 1;
                            drop(s);
                            error_json("internal server error", 500)
                        }
                        Err(_) => error_json("internal server error", 500),
                    }
                } else {
                    serve_static(&url, &site_dir)
                }
            }
        },
    );

    // Limit request body size to 10 MiB to prevent memory exhaustion attacks
    let app = app.layer(tower_http::limit::RequestBodyLimitLayer::new(
        10 * 1024 * 1024,
    ));

    let app = app.into_make_service_with_connect_info::<std::net::SocketAddr>();

    eprintln!("Wardex server ready on http://localhost:{port}");

    axum::serve(listener, app)
        .with_graceful_shutdown(async move {
            let timeout = tokio::time::Duration::from_secs(shutdown_timeout_secs);
            shutdown_notify.notified().await;
            log::info!("Graceful shutdown initiated (timeout={shutdown_timeout_secs}s)…");
            tokio::time::sleep(timeout).await;
            log::info!("Shutdown timeout reached, closing connections");
        })
        .await
        .map_err(|e| format!("server error: {e}"))?;

    // ── Graceful shutdown: flush outstanding data to durable storage ──
    flush_to_storage(&state);

    Ok(())
}

/// Spawn a test server on a random port. Returns `(port, token)`.
/// The server runs in a background thread.
#[doc(hidden)]
fn spawn_test_server_with_state() -> (u16, String, Arc<Mutex<AppState>>) {
    let (tx, rx) = std::sync::mpsc::channel();
    // Find a free port
    let tmp_listener = std::net::TcpListener::bind("127.0.0.1:0").expect("bind test server");
    let port = tmp_listener.local_addr().expect("local addr").port();
    drop(tmp_listener);
    let token = generate_token();
    let state_root = PathBuf::from(format!("/tmp/wardex_test_{port}"));
    let _ = std::fs::remove_dir_all(&state_root);
    std::fs::create_dir_all(&state_root).expect("create test state root");
    let config_path = state_root.join("wardex.toml");
    let session_store = crate::auth::SessionStore::with_persistence_key(
        &session_store_path(&config_path),
        Some(load_or_create_session_seal_key(&config_path)),
    );
    let user_preferences = UserPreferencesStore::new(&user_preferences_store_path(&config_path));
    let model_registry_dir = model_registry_path(&config_path);
    let detection_feedback_path = detection_feedback_store_path(&config_path);
    let state = Arc::new(Mutex::new(AppState {
        detector: AnomalyDetector::default(),
        checkpoints: CheckpointStore::new(10),
        device: DeviceController::default(),
        replay: ReplayBuffer::new(200),
        proofs: ProofRegistry::new(),
        last_report: None,
        last_failover_drill: None,
        token: token.clone(),
        token_issued_at: std::time::Instant::now(),
        session_store,
        oidc_providers: HashMap::new(),
        user_preferences,
        swarm: SwarmNode::new("test-node-0"),
        cluster: ClusterNode::new(Config::default().cluster.clone()),
        enforcement: EnforcementEngine::new(),
        threat_intel: ThreatIntelStore::new(),
        digital_twin: DigitalTwinEngine::new(),
        compliance: ComplianceManager::new(),
        multi_tenant: MultiTenantManager::new(),
        energy: EnergyBudget::new(500.0),
        side_channel: SideChannelDetector::new(),
        key_rotation: KeyRotationManager::new(3600),
        privacy: PrivacyAccountant::new(10.0),
        policy_vm: PolicyVm::default(),
        fingerprint: None,
        monitor: Monitor::new(),
        drift: DriftDetector::new(0.005, 50.0),
        deception: DeceptionEngine::new(),
        patches: PatchManager::new(),
        causal: CausalGraph::new(),
        listener_mode: ListenerMode::Plain { port },
        config: Config::default(),
        config_path,
        alerts: VecDeque::new(),
        server_start: std::time::Instant::now(),
        agent_registry: AgentRegistry::new(&state_root.join("agents.json").to_string_lossy()),
        event_store: EventStore::with_persistence(
            1000,
            state_root.join("events.json").to_string_lossy().to_string(),
        ),
        clickhouse_store: None,
        policy_store: PolicyStore::new(),
        update_manager: UpdateManager::new(&state_root.join("updates").to_string_lossy()),
        remote_deployments: load_remote_deployments(
            &state_root.join("deployments.json").to_string_lossy(),
        ),
        deployment_store_path: state_root
            .join("deployments.json")
            .to_string_lossy()
            .to_string(),
        siem_connector: SiemConnector::new(crate::siem::SiemConfig::default()),
        taxii_client: crate::siem::TaxiiClient::new(crate::siem::TaxiiConfig::default()),
        local_telemetry: VecDeque::new(),
        local_host_info: detect_platform(),
        last_inventory: None,
        last_inventory_at_ms: 0,
        velocity: VelocityDetector::new(60, 2.5),
        entropy: EntropyDetector::new(60, 8),
        compound: CompoundThreatDetector::default(),
        shutdown: Arc::new(AtomicBool::new(false)),
        rate_limiter: RateLimiter::new(360, 60),
        audit_log: AuditLog::new(1000),
        incident_store: IncidentStore::new(&state_root.join("incidents.json").to_string_lossy()),
        agent_logs: HashMap::new(),
        agent_logs_last_access: HashMap::new(),
        agent_inventories: HashMap::new(),
        report_store: crate::report::ReportStore::new(
            &state_root.join("reports.json").to_string_lossy(),
        ),
        support_store: SupportStore::new(&state_root.join("support.json").to_string_lossy()),
        sigma_engine: SigmaEngine::new(),
        response_orchestrator: ResponseOrchestrator::new(),
        feature_flags: FeatureFlagRegistry::new(),
        process_tree: ProcessTree::new("localhost"),
        spool: EncryptedSpool::new(
            &sha2::Sha256::digest(format!("spool-key-{token}").as_bytes()),
            10_000,
        ),
        rbac: RbacStore::new(),
        case_store: CaseStore::new(&state_root.join("cases.json").to_string_lossy()),
        alert_queue: AlertQueue::new(),
        approval_log: ApprovalLog::new(),
        dead_letter_queue: DeadLetterQueue::new(500),
        enterprise: EnterpriseStore::new(&state_root.join("enterprise.json").to_string_lossy()),
        request_count: 0,
        error_count: 0,
        beacon_detector: crate::beacon::BeaconDetector::default(),
        ueba_engine: crate::ueba::UebaEngine::default(),
        kill_chain_analyzer: crate::kill_chain::KillChainAnalyzer::new(),
        lateral_detector: crate::lateral::LateralMovementDetector::default(),
        playbook_engine: crate::playbook::PlaybookEngine::new(),
        live_response_engine: crate::live_response::LiveResponseEngine::default(),
        remediation_engine: crate::remediation::RemediationEngine::new(),
        escalation_engine: crate::escalation::EscalationEngine::new(),
        kernel_event_stream: crate::kernel_events::KernelEventStream::new(10_000),
        last_alert_analysis: None,
        storage: SharedStorage::open(state_root.join("storage").to_str().unwrap_or("var/storage"))
            .or_else(|_| SharedStorage::open("/tmp/wardex_storage"))
            .expect("failed to initialise test storage"),
        slow_attack: crate::detector::SlowAttackDetector::default(),
        ransomware: crate::ransomware::RansomwareDetector::default(),
        mitre_coverage: crate::mitre_coverage::MitreCoverageTracker::new(),
        tuning_profile: crate::detector::TuningProfile::default(),
        fp_feedback: crate::alert_analysis::FpFeedbackStore::new(),
        vulnerability_scanner: crate::vulnerability::VulnerabilityScanner::new(),
        ndr_engine: crate::ndr::NdrEngine::new(crate::ndr::NdrConfig::default()),
        container_detector: crate::container::ContainerDetector::new(),
        cert_monitor: crate::cert_monitor::CertMonitor::new(),
        config_drift_detector: crate::config_drift::ConfigDriftDetector::new(),
        asset_inventory: crate::cloud_inventory::AssetInventory::new(),
        efficacy_tracker: crate::detection_efficacy::EfficacyTracker::new(100_000),
        workflow_store: crate::investigation::WorkflowStore::new(),
        llm_analyst: Arc::new(Mutex::new(load_llm_analyst_from_env())),
        model_registry: crate::ml_engine::ModelRegistry::new(&model_registry_dir),
        detection_feedback: crate::detection_feedback::DetectionFeedbackStore::new(
            &detection_feedback_path,
        ),
        malware_hash_db: crate::malware_signatures::MalwareHashDb::new(),
        malware_scanner: crate::malware_scanner::MalwareScanner::new(),
        yara_engine: crate::yara_engine::YaraEngine::new(),
        api_analytics: crate::api_analytics::ApiAnalytics::new(),
        trace_collector: crate::telemetry::TraceCollector::new(10000),
        feed_engine: crate::feed_ingestion::FeedIngestionEngine::new(),
        playbook_dsl: crate::playbook_dsl::PlaybookDslStore::new(),
        image_inventory: crate::container_image::ImageInventory::new(),
        quarantine_store: crate::quarantine::QuarantineStore::new(),
        lifecycle_manager: crate::agent_lifecycle::LifecycleManager::new(
            crate::agent_lifecycle::LifecycleConfig::default(),
        ),
        decay_config: crate::ioc_decay::DecayConfig::default(),
        dns_analyzer: crate::dns_threat::DnsAnalyzer::new(),
        alert_broadcaster: crate::ws_stream::AlertBroadcaster::new(),
        extra: HashMap::new(),
    }));
    {
        let mut s = state.lock().unwrap_or_else(|e| e.into_inner());
        let effective_rules = s.enterprise.effective_sigma_rules();
        s.sigma_engine.replace_rules(effective_rules);
    }
    spawn_enterprise_hunt_scheduler(&state);
    spawn_cluster_runtime_loop(&state);
    let site_dir = PathBuf::from("site");
    let shutdown = {
        let s = state.lock().unwrap_or_else(|e| e.into_inner());
        s.shutdown.clone()
    };
    let server_state = Arc::clone(&state);
    std::thread::spawn(move || {
        let rt = tokio::runtime::Runtime::new().expect("tokio runtime");
        rt.block_on(async move {
            let shared_state = Arc::clone(&server_state);
            let shared_site = site_dir.clone();
            let shutdown_flag = shutdown.clone();

            use axum::Router;
            use axum::extract::ConnectInfo;

            let app = Router::new().fallback(
                move |method: HttpMethod,
                      uri: axum::http::Uri,
                      headers: HeaderMap,
                      ConnectInfo(addr): ConnectInfo<std::net::SocketAddr>,
                      body: axum::body::Bytes| {
                    let state = shared_state.clone();
                    let site_dir = shared_site.clone();
                    async move {
                        let url = uri.to_string();
                        let remote_addr = addr.ip().to_string();

                        {
                            let method_compat = Method::from_http(&method);
                            let mut s = match state.lock() {
                                Ok(g) => g,
                                Err(e) => e.into_inner(),
                            };
                            s.request_count += 1;
                            if !s.rate_limiter.check(&remote_addr, &method_compat, &url) {
                                drop(s);
                                return error_json("rate limit exceeded", 429);
                            }
                        }

                        if method == HttpMethod::OPTIONS {
                            let origin = cors_origin();
                            return Response::builder()
                                .status(204)
                                .header("Access-Control-Allow-Origin", origin)
                                .header(
                                    "Access-Control-Allow-Methods",
                                    "GET, POST, PUT, DELETE, PATCH, OPTIONS",
                                )
                                .header(
                                    "Access-Control-Allow-Headers",
                                    "Content-Type, Authorization",
                                )
                                .body(Body::empty())
                                .unwrap_or_else(|_| Response::new(Body::empty()));
                        }

                        if url.starts_with("/api/") {
                            let m = Method::from_http(&method);
                            handle_api(m, &url, &headers, &body, &remote_addr, &state)
                        } else {
                            serve_static(&url, &site_dir)
                        }
                    }
                },
            );

            let listener = tokio::net::TcpListener::bind(format!("127.0.0.1:{port}"))
                .await
                .expect("bind test listener");
            tx.send(()).ok();
            let app = app.into_make_service_with_connect_info::<std::net::SocketAddr>();
            axum::serve(listener, app)
                .with_graceful_shutdown(async move {
                    loop {
                        tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
                        if shutdown_flag.load(Ordering::Relaxed) {
                            break;
                        }
                    }
                })
                .await
                .ok();
        });
    });
    // Wait for server to be listening
    let _ = rx.recv_timeout(std::time::Duration::from_secs(5));
    // Small delay to let the listener actually start accepting
    std::thread::sleep(std::time::Duration::from_millis(50));
    (port, token, state)
}

pub fn spawn_test_server() -> (u16, String) {
    let (port, token, _state) = spawn_test_server_with_state();
    (port, token)
}

#[doc(hidden)]
pub fn spawn_test_server_with_seeded_alerts(alerts: Vec<AlertRecord>) -> (u16, String) {
    let (port, token, state) = spawn_test_server_with_state();
    if !alerts.is_empty() {
        let mut s = state.lock().unwrap_or_else(|e| e.into_inner());
        for alert in alerts {
            if s.alerts.len() >= 10_000 {
                s.alerts.pop_front();
            }
            s.alerts.push_back(alert);
        }
    }
    (port, token)
}

#[doc(hidden)]
pub fn spawn_test_server_with_seeded_remote_installs(
    installs: Vec<RemoteInstallRecord>,
) -> (u16, String) {
    let (port, token, state) = spawn_test_server_with_state();
    if !installs.is_empty() {
        let s = state.lock().unwrap_or_else(|e| e.into_inner());
        let _ = save_stored_json(&s.storage, FLEET_REMOTE_INSTALLS_KEY, &installs);
    }
    (port, token)
}

#[doc(hidden)]
pub fn spawn_test_server_with_live_rollback_enabled() -> (u16, String) {
    let (port, token, state) = spawn_test_server_with_state();
    {
        let mut s = state.lock().unwrap_or_else(|e| e.into_inner());
        s.config.remediation.allow_live_rollback = true;
    }
    (port, token)
}

#[doc(hidden)]
pub fn spawn_test_server_with_live_rollback_execution_enabled() -> (u16, String) {
    let (port, token, state) = spawn_test_server_with_state();
    {
        let mut s = state.lock().unwrap_or_else(|e| e.into_inner());
        s.config.remediation.allow_live_rollback = true;
        s.config.remediation.execute_live_rollback_commands = true;
    }
    (port, token)
}

/// Flush in-memory alerts, audit entries, and event store to the SQLite
/// storage backend so nothing is lost on shutdown.
fn flush_to_storage(state: &Arc<Mutex<AppState>>) {
    let s = match state.lock() {
        Ok(g) => g,
        Err(e) => e.into_inner(),
    };
    let storage = s.storage.clone();
    let alerts: Vec<_> = s.alerts.iter().cloned().collect();
    let audit_entries: Vec<_> = s.audit_log.entries.iter().cloned().collect();
    let events: Vec<_> = s.event_store.all_events().to_vec();
    let hostname = s.local_host_info.hostname.clone();
    drop(s);

    let mut stored = 0usize;
    let mut errors = 0usize;

    // Flush in-memory alerts
    for (i, alert) in alerts.iter().enumerate() {
        let stored_alert = crate::storage::StoredAlert {
            id: format!("mem-{}-{}", hostname, i),
            timestamp: alert.timestamp.clone(),
            device_id: hostname.clone(),
            score: alert.score as f64,
            level: alert.level.clone(),
            reasons: alert.reasons.clone(),
            acknowledged: false,
            assigned_to: None,
            case_id: None,
            tenant_id: "default".into(),
        };
        match storage.with(|store| store.insert_alert(stored_alert)) {
            Ok(()) => stored += 1,
            Err(e) => {
                // Conflict (duplicate) is OK — alert was already persisted
                if e.code != crate::storage::StorageErrorCode::Conflict {
                    errors += 1;
                }
            }
        }
    }

    // Flush API audit log entries
    let mut audit_stored = 0usize;
    for entry in &audit_entries {
        let action = format!("{} {}", entry.method, entry.path);
        if storage
            .with(|store| {
                store.append_audit(
                    &entry.source_ip,
                    &action,
                    Some(&entry.path),
                    Some(&format!(
                        "status={} auth={}",
                        entry.status_code, entry.auth_used
                    )),
                    "default",
                )
            })
            .is_ok()
        {
            audit_stored += 1;
        }
    }

    // Flush forwarded events as stored alerts
    let mut event_stored = 0usize;
    for event in &events {
        let stored_alert = crate::storage::StoredAlert {
            id: format!("evt-{}", event.id),
            timestamp: event.received_at.clone(),
            device_id: event.agent_id.clone(),
            score: event.alert.score as f64,
            level: event.alert.level.clone(),
            reasons: event.alert.reasons.clone(),
            acknowledged: false,
            assigned_to: None,
            case_id: None,
            tenant_id: "default".into(),
        };
        match storage.with(|store| store.insert_alert(stored_alert)) {
            Ok(()) => event_stored += 1,
            Err(e) => {
                if e.code != crate::storage::StorageErrorCode::Conflict {
                    errors += 1;
                }
            }
        }
    }

    log::info!(
        "Shutdown flush: {stored} alerts, {audit_stored} audit entries, {event_stored} events written to storage ({errors} errors)",
    );
}

fn generate_token() -> String {
    use rand::Rng;
    let mut rng = rand::thread_rng();
    let bytes: Vec<u8> = (0..32).map(|_| rng.r#gen()).collect();
    hex::encode(bytes)
}

fn backup_file_record(path: &Path) -> Result<crate::backup::BackupRecord, String> {
    let metadata =
        fs::metadata(path).map_err(|e| format!("failed to read backup metadata: {e}"))?;
    let contents = fs::read(path).map_err(|e| format!("failed to read backup file: {e}"))?;
    let name = path
        .file_name()
        .and_then(|value| value.to_str())
        .ok_or_else(|| "invalid backup file name".to_string())?
        .to_string();
    let modified = metadata.modified().unwrap_or(std::time::UNIX_EPOCH);
    let timestamp = chrono::DateTime::<chrono::Utc>::from(modified).to_rfc3339();

    Ok(crate::backup::BackupRecord {
        name,
        timestamp,
        size_bytes: metadata.len(),
        checksum: crate::audit::sha256_hex(&contents),
        verified: true,
    })
}

fn is_runtime_backup_file(path: &Path) -> bool {
    if !path.is_file() {
        return false;
    }

    match path.file_name().and_then(|value| value.to_str()) {
        Some(file_name) => file_name.starts_with("wardex_backup_") && file_name.ends_with(".db"),
        None => false,
    }
}

fn backup_records_in_dir(backup_path: &Path) -> Vec<crate::backup::BackupRecord> {
    let mut records = fs::read_dir(backup_path)
        .ok()
        .into_iter()
        .flat_map(|entries| entries.filter_map(Result::ok))
        .map(|entry| entry.path())
        .filter(|path| is_runtime_backup_file(path))
        .filter_map(|path| backup_file_record(&path).ok())
        .collect::<Vec<_>>();
    records.sort_by(|a, b| b.timestamp.cmp(&a.timestamp));
    records
}

#[derive(Debug, Clone, serde::Serialize)]
struct BackupStatusSnapshot {
    enabled: bool,
    retention_count: u32,
    path: String,
    schedule_cron: String,
    observed_backups: usize,
    latest_backup_at: Option<String>,
}

impl BackupStatusSnapshot {
    fn gather() -> Self {
        let config = crate::backup::BackupConfig::default();
        let backup_path = Path::new(&config.path);
        let records = backup_records_in_dir(backup_path);

        Self {
            enabled: config.enabled,
            retention_count: config.retention_count,
            path: config.path,
            schedule_cron: config.schedule_cron,
            observed_backups: records.len(),
            latest_backup_at: records.first().map(|record| record.timestamp.clone()),
        }
    }
}

#[derive(Debug, Clone, serde::Serialize)]
struct ControlPlaneClusterSnapshot {
    node_id: String,
    role: String,
    leader_id: Option<String>,
    peers_total: usize,
    peers_reachable: usize,
    commit_index: u64,
    healthy: bool,
}

fn control_plane_cluster_snapshot(state: &AppState) -> Option<ControlPlaneClusterSnapshot> {
    let health = state.cluster.health();
    if health.peers_total == 0 {
        return None;
    }

    Some(ControlPlaneClusterSnapshot {
        node_id: health.node_id.to_string(),
        role: health.role.to_string(),
        leader_id: health.leader_id.map(|leader_id| leader_id.to_string()),
        peers_total: health.peers_total,
        peers_reachable: health.peers_reachable,
        commit_index: health.commit_index,
        healthy: health.healthy,
    })
}

fn control_plane_failover_history_preview(state: &AppState) -> serde_json::Value {
    let backup_status = BackupStatusSnapshot::gather();
    let control_plane = ControlPlanePostureSnapshot::gather(state, &backup_status);
    let drills = control_plane.failover_drill_history.clone();
    let passed = drills
        .iter()
        .filter(|drill| drill.status == "passed")
        .count();
    let failed = drills
        .iter()
        .filter(|drill| drill.status == "failed")
        .count();

    serde_json::json!({
        "generated_at": chrono::Utc::now().to_rfc3339(),
        "kind": "control_plane_failover_history",
        "topology": control_plane.topology,
        "orchestration_scope": control_plane.orchestration_scope,
        "ha_mode": control_plane.ha_mode,
        "documented_failover": control_plane.documented_failover,
        "recovery_status": control_plane.recovery_status,
        "cluster": control_plane.cluster,
        "latest_drill": control_plane.failover_drill,
        "drill_count": drills.len(),
        "passed_count": passed,
        "failed_count": failed,
        "history": drills,
    })
}

fn build_report_run_preview(
    state: &mut AppState,
    request: &serde_json::Value,
    execution_context_json: serde_json::Value,
) -> serde_json::Value {
    let kind = request["kind"].as_str().unwrap_or("executive_status");
    match kind {
        "control_plane_failover_history" => control_plane_failover_history_preview(state),
        _ => {
            state.agent_registry.refresh_staleness();
            let open_incidents = state
                .incident_store
                .list()
                .iter()
                .filter(|incident| {
                    matches!(
                        incident.status,
                        crate::incident::IncidentStatus::Open
                            | crate::incident::IncidentStatus::Investigating
                    )
                })
                .count();
            let offline_agents = state
                .agent_registry
                .list()
                .iter()
                .filter(|agent| {
                    matches!(
                        agent.status,
                        crate::enrollment::AgentStatus::Offline
                            | crate::enrollment::AgentStatus::Stale
                    )
                })
                .count();
            let queue_pending = state.alert_queue.pending().len();
            serde_json::json!({
                "generated_at": chrono::Utc::now().to_rfc3339(),
                "kind": kind,
                "scope": request["scope"].as_str().unwrap_or("global"),
                "queue_pending": queue_pending,
                "open_incidents": open_incidents,
                "offline_agents": offline_agents,
                "pending_approvals": state.response_orchestrator.pending_requests().len(),
                "stored_reports": state.report_store.list().len(),
                "execution_context": execution_context_json,
                "executive_summary": state.report_store.executive_summary(&state.incident_store),
            })
        }
    }
}

fn failover_drill_orchestration_scope(topology: &str) -> String {
    if topology == "standalone" {
        "standalone_reference".to_string()
    } else {
        "non_standalone_orchestrated".to_string()
    }
}

fn failover_drill_type(topology: &str) -> &'static str {
    if topology == "standalone" {
        "warm_standby_restore_dry_run"
    } else {
        "leader_handoff_restore_dry_run"
    }
}

fn control_plane_ha_mode(cluster: Option<&ControlPlaneClusterSnapshot>) -> &'static str {
    match cluster.map(|cluster| cluster.role.as_str()) {
        None => "active_passive_reference",
        Some("leader") => "leader_handoff_primary",
        Some("follower") => "external_standby",
        Some("candidate") => "leader_election",
        Some(_) => "non_standalone_orchestrated",
    }
}

fn control_plane_recovery_status(
    cluster: Option<&ControlPlaneClusterSnapshot>,
    durable_storage: bool,
    restore_ready: bool,
) -> String {
    if !durable_storage || !restore_ready {
        return "review".to_string();
    }

    match cluster {
        None => "ready_for_documented_failover".to_string(),
        Some(cluster) if !cluster.healthy => "review".to_string(),
        Some(cluster) if cluster.role == "leader" => "ready_for_leader_handoff".to_string(),
        Some(cluster) if cluster.role == "follower" => "ready_as_external_standby".to_string(),
        Some(_) => "leader_election_in_progress".to_string(),
    }
}

fn control_plane_documented_failover(
    cluster: Option<&ControlPlaneClusterSnapshot>,
) -> &'static str {
    if cluster.is_some() {
        "leader_handoff_or_external_standby_restore"
    } else {
        "warm_standby_restore"
    }
}

fn failover_drill_summary(
    durable_storage_verified: bool,
    backup_artifact_verified: bool,
    checkpoint_artifact_verified: bool,
) -> String {
    match (
        durable_storage_verified,
        backup_artifact_verified,
        checkpoint_artifact_verified,
    ) {
        (true, true, true) => "Validated durable event storage with both backup and checkpoint artifacts for the documented failover path.".to_string(),
        (true, true, false) => "Validated durable event storage with backup artifacts for the documented failover path.".to_string(),
        (true, false, true) => "Validated durable event storage with checkpoint artifacts for the documented failover path.".to_string(),
        (false, false, false) => "Failover drill failed because durable event storage is disabled and no backup or checkpoint artifacts were available.".to_string(),
        (false, _, _) => "Failover drill failed because durable event storage is disabled.".to_string(),
        (true, false, false) => "Failover drill failed because no backup or checkpoint artifacts were available for recovery validation.".to_string(),
    }
}

impl FailoverDrillRecord {
    fn not_run(topology: &str) -> Self {
        Self {
            drill_type: failover_drill_type(topology).to_string(),
            orchestration_scope: failover_drill_orchestration_scope(topology),
            status: "not_run".to_string(),
            last_run_at: None,
            actor: None,
            summary: "No automated failover drill has been recorded yet.".to_string(),
            artifact_source: "none".to_string(),
            durable_storage_verified: false,
            backup_artifact_verified: false,
            checkpoint_artifact_verified: false,
        }
    }

    fn evaluate(state: &AppState, backup: &BackupStatusSnapshot, actor: &str) -> Self {
        let topology = if control_plane_cluster_snapshot(state).is_some() {
            "clustered"
        } else {
            "standalone"
        };
        let durable_storage_verified = state.event_store.has_persistence();
        let backup_artifact_verified = backup.observed_backups > 0;
        let checkpoint_artifact_verified = !state.checkpoints.is_empty();
        let artifact_source = match (backup_artifact_verified, checkpoint_artifact_verified) {
            (true, true) => "backup_and_checkpoint",
            (true, false) => "backup",
            (false, true) => "checkpoint",
            (false, false) => "none",
        };

        Self {
            drill_type: failover_drill_type(topology).to_string(),
            orchestration_scope: failover_drill_orchestration_scope(topology),
            status: if durable_storage_verified
                && (backup_artifact_verified || checkpoint_artifact_verified)
            {
                "passed".to_string()
            } else {
                "failed".to_string()
            },
            last_run_at: Some(chrono::Utc::now().to_rfc3339()),
            actor: Some(actor.to_string()),
            summary: failover_drill_summary(
                durable_storage_verified,
                backup_artifact_verified,
                checkpoint_artifact_verified,
            ),
            artifact_source: artifact_source.to_string(),
            durable_storage_verified,
            backup_artifact_verified,
            checkpoint_artifact_verified,
        }
    }
}

#[derive(Debug, Clone, serde::Serialize)]
struct ControlPlanePostureSnapshot {
    topology: String,
    orchestration_scope: String,
    ha_mode: String,
    leader: bool,
    durable_storage: bool,
    event_store_path: String,
    backup_schedule_cron: String,
    observed_backups: usize,
    latest_backup_at: Option<String>,
    checkpoint_count: usize,
    latest_checkpoint_at: Option<String>,
    restore_ready: bool,
    recovery_status: String,
    documented_failover: String,
    recovery_targets: Vec<RecoveryTargetEntry>,
    cluster: Option<ControlPlaneClusterSnapshot>,
    failover_drill: FailoverDrillRecord,
    failover_drill_history: Vec<FailoverDrillRecord>,
}

#[derive(Debug, Clone, serde::Serialize)]
struct RecoveryTargetEntry {
    scenario: String,
    rto: String,
    rpo: String,
}

impl ControlPlanePostureSnapshot {
    fn gather(state: &AppState, backup: &BackupStatusSnapshot) -> Self {
        let checkpoint_count = state.checkpoints.len();
        let latest_checkpoint_at = state.checkpoints.latest().map(|entry| {
            chrono::DateTime::<chrono::Utc>::from(
                std::time::UNIX_EPOCH + std::time::Duration::from_millis(entry.timestamp_ms),
            )
            .to_rfc3339()
        });
        let durable_storage = state.event_store.has_persistence();
        let restore_ready = backup.observed_backups > 0 || checkpoint_count > 0;
        let cluster = control_plane_cluster_snapshot(state);
        let topology = if cluster.is_some() {
            "clustered".to_string()
        } else {
            "standalone".to_string()
        };
        let orchestration_scope = failover_drill_orchestration_scope(&topology);
        let mut failover_drill_history = state.support_store.failover_drills().to_vec();
        if failover_drill_history.is_empty()
            && let Some(drill) = state.last_failover_drill.clone()
        {
            failover_drill_history.push(drill);
        }
        let failover_drill = state
            .support_store
            .latest_failover_drill()
            .or_else(|| state.last_failover_drill.clone())
            .unwrap_or_else(|| FailoverDrillRecord::not_run(&topology));
        let recovery_targets = vec![
            RecoveryTargetEntry {
                scenario: "Config corruption".to_string(),
                rto: "< 5 min".to_string(),
                rpo: "Last backup".to_string(),
            },
            RecoveryTargetEntry {
                scenario: "Full disk loss".to_string(),
                rto: "< 15 min".to_string(),
                rpo: "Daily backup (24 h)".to_string(),
            },
            RecoveryTargetEntry {
                scenario: "Key compromise".to_string(),
                rto: "< 30 min".to_string(),
                rpo: "Rotate + re-enroll agents".to_string(),
            },
            RecoveryTargetEntry {
                scenario: "Binary corruption".to_string(),
                rto: "< 10 min".to_string(),
                rpo: "Redeploy from CI artefact".to_string(),
            },
        ];

        Self {
            topology,
            orchestration_scope,
            ha_mode: control_plane_ha_mode(cluster.as_ref()).to_string(),
            leader: cluster
                .as_ref()
                .map(|cluster| cluster.role == "leader")
                .unwrap_or(true),
            durable_storage,
            event_store_path: state
                .event_store
                .storage_path()
                .unwrap_or("memory")
                .to_string(),
            backup_schedule_cron: backup.schedule_cron.clone(),
            observed_backups: backup.observed_backups,
            latest_backup_at: backup.latest_backup_at.clone(),
            checkpoint_count,
            latest_checkpoint_at,
            restore_ready,
            recovery_status: control_plane_recovery_status(
                cluster.as_ref(),
                durable_storage,
                restore_ready,
            ),
            documented_failover: control_plane_documented_failover(cluster.as_ref()).to_string(),
            recovery_targets,
            cluster,
            failover_drill,
            failover_drill_history,
        }
    }

    fn ha_mode_payload(&self) -> serde_json::Value {
        let status = match self.cluster.as_ref() {
            Some(cluster) if self.durable_storage && self.restore_ready && cluster.healthy => {
                "ready_for_orchestrated_failover"
            }
            None if self.durable_storage && self.restore_ready => "ready_for_active_passive",
            _ => "review",
        };
        serde_json::json!({
            "mode": self.ha_mode,
            "topology": self.topology,
            "orchestration_scope": self.orchestration_scope,
            "status": status,
            "leader": self.leader,
            "recovery_status": self.recovery_status,
            "documented_failover": self.documented_failover,
            "observed_backups": self.observed_backups,
            "latest_backup_at": self.latest_backup_at,
            "checkpoint_count": self.checkpoint_count,
            "latest_checkpoint_at": self.latest_checkpoint_at,
            "restore_ready": self.restore_ready,
            "cluster": self.cluster,
            "failover_drill_history_count": self.failover_drill_history.len(),
            "failover_drill": self.failover_drill.clone(),
        })
    }
}

/// Scan text for common PII patterns (email, IPv4, SSN, credit card).
/// Returns a list of category names found.
fn scan_pii(text: &str) -> Vec<String> {
    let mut categories = Vec::new();

    // Email pattern
    let has_email = text.split_whitespace().any(|w| {
        let w = w.trim_matches(|c: char| {
            !c.is_alphanumeric() && c != '@' && c != '.' && c != '_' && c != '-'
        });
        w.contains('@') && w.contains('.') && w.len() > 5
    });
    if has_email {
        categories.push("email".into());
    }

    // SSN pattern (###-##-####)
    let has_ssn = text.as_bytes().windows(11).any(|w| {
        w.len() == 11
            && w[0].is_ascii_digit()
            && w[1].is_ascii_digit()
            && w[2].is_ascii_digit()
            && w[3] == b'-'
            && w[4].is_ascii_digit()
            && w[5].is_ascii_digit()
            && w[6] == b'-'
            && w[7].is_ascii_digit()
            && w[8].is_ascii_digit()
            && w[9].is_ascii_digit()
            && w[10].is_ascii_digit()
    });
    if has_ssn {
        categories.push("ssn".into());
    }

    // Credit card pattern (4 groups of 4 digits separated by spaces or dashes)
    let digits_only: String = text.chars().filter(|c| c.is_ascii_digit()).collect();
    if digits_only.len() >= 13 {
        // Luhn check on first 16-digit sequence
        let candidate: Vec<u8> = digits_only.bytes().take(16).map(|b| b - b'0').collect();
        if candidate.len() >= 13 {
            let mut sum = 0u32;
            let mut double = false;
            for &d in candidate.iter().rev() {
                let mut n = d as u32;
                if double {
                    n *= 2;
                    if n > 9 {
                        n -= 9;
                    }
                }
                sum += n;
                double = !double;
            }
            if sum.is_multiple_of(10) {
                categories.push("credit_card".into());
            }
        }
    }

    // IPv4 addresses (not in RFC 1918 private ranges to reduce false positives)
    let has_public_ip = text.split_whitespace().any(|w| {
        let parts: Vec<&str> = w
            .trim_matches(|c: char| !c.is_ascii_digit() && c != '.')
            .split('.')
            .collect();
        if parts.len() == 4 && parts.iter().all(|p| p.parse::<u8>().is_ok()) {
            let first: u8 = parts[0].parse().unwrap_or(0);
            let second: u8 = parts[1].parse().unwrap_or(0);
            // Skip private ranges
            !(first == 10
                || first == 127
                || (first == 172 && (16..=31).contains(&second))
                || (first == 192 && second == 168))
        } else {
            false
        }
    });
    if has_public_ip {
        categories.push("ip_address".into());
    }

    categories
}

fn cors_origin() -> String {
    let origin =
        std::env::var("SENTINEL_CORS_ORIGIN").unwrap_or_else(|_| "http://localhost".into());
    // Block wildcard CORS origin — credentials must not use "*"
    if origin == "*" {
        return "http://localhost".into();
    }
    // Validate origin looks like a URL scheme
    if origin.starts_with("http://") || origin.starts_with("https://") {
        origin
    } else {
        "http://localhost".into()
    }
}

fn security_headers(builder: axum::http::response::Builder) -> axum::http::response::Builder {
    let origin = cors_origin();
    builder
        .header("Access-Control-Allow-Origin", origin)
        .header("Vary", "Origin")
        .header("X-Content-Type-Options", "nosniff")
        .header("X-Frame-Options", "DENY")
        .header("Cache-Control", "no-store")
        .header("Referrer-Policy", "strict-origin-when-cross-origin")
        .header("Permissions-Policy", "camera=(), microphone=(), geolocation=()")
        .header(
            "Strict-Transport-Security",
            "max-age=63072000; includeSubDomains; preload",
        )
        .header(
            "Content-Security-Policy",
            "default-src 'self'; script-src 'self'; style-src 'self' 'unsafe-inline'; img-src 'self' data:; connect-src 'self'; font-src 'self'; frame-ancestors 'none'",
        )
        .header("Cross-Origin-Opener-Policy", "same-origin")
        .header("Cross-Origin-Resource-Policy", "same-origin")
        .header("X-DNS-Prefetch-Control", "off")
        .header("X-Permitted-Cross-Domain-Policies", "none")
}

fn safe_body(builder: axum::http::response::Builder, body: Body) -> Response<Body> {
    builder.body(body).unwrap_or_else(|_| {
        Response::builder()
            .status(500)
            .body(Body::from("internal server error"))
            .expect("fallback response must build")
    })
}

fn json_response(body: &str, status: u16) -> Response<Body> {
    safe_body(
        security_headers(Response::builder().status(status))
            .header("Content-Type", "application/json"),
        Body::from(body.to_owned()),
    )
}

fn error_json(message: &str, status: u16) -> Response<Body> {
    let code = match status {
        400 => "VALIDATION_ERROR",
        401 => "AUTH_REQUIRED",
        403 => "FORBIDDEN",
        404 => "NOT_FOUND",
        409 => "CONFLICT",
        413 => "PAYLOAD_TOO_LARGE",
        429 => "RATE_LIMITED",
        500 => "INTERNAL_ERROR",
        503 => "SERVICE_UNAVAILABLE",
        _ => "ERROR",
    };
    let body = format!(
        r#"{{"error":"{}","code":"{}"}}"#,
        message.replace('"', "\\\""),
        code
    );
    json_response(&body, status)
}

fn text_response(body: &str, status: u16) -> Response<Body> {
    safe_body(
        security_headers(Response::builder().status(status))
            .header("Content-Type", "text/plain; charset=utf-8"),
        Body::from(body.to_owned()),
    )
}

fn csv_response(body: &str, status: u16) -> Response<Body> {
    safe_body(
        security_headers(Response::builder().status(status))
            .header("Content-Type", "text/csv; charset=utf-8"),
        Body::from(body.to_owned()),
    )
}

#[derive(Debug, Clone, serde::Serialize, PartialEq)]
struct AlertProcessPivot {
    pid: u32,
    ppid: Option<u32>,
    name: String,
    display_name: String,
    user: Option<String>,
    group: Option<String>,
    cpu_percent: Option<f32>,
    mem_percent: Option<f32>,
    hostname: String,
    platform: String,
    cmd_line: Option<String>,
    exe_path: Option<String>,
}

fn normalized_process_token(value: &str) -> String {
    let token = value
        .split_whitespace()
        .next()
        .unwrap_or(value)
        .trim_matches('"');
    let base = token
        .rsplit(['/', '\\'])
        .next()
        .unwrap_or(token)
        .trim_end_matches(':');
    base.trim_end_matches(".exe").to_ascii_lowercase()
}

fn host_matches_local(alert_hostname: &str, local_hostname: &str) -> bool {
    if alert_hostname.eq_ignore_ascii_case(local_hostname) {
        return true;
    }
    let alert_short = alert_hostname.split('.').next().unwrap_or(alert_hostname);
    let local_short = local_hostname.split('.').next().unwrap_or(local_hostname);
    alert_short.eq_ignore_ascii_case(local_short)
}

fn extract_alert_process_names(entities: &[crate::entity_extract::ExtractedEntity]) -> Vec<String> {
    let mut seen = HashSet::new();
    entities
        .iter()
        .filter(|entity| {
            matches!(
                entity.entity_type,
                crate::entity_extract::EntityType::ProcessName
            )
        })
        .filter_map(|entity| {
            let normalized = normalized_process_token(&entity.value);
            if normalized.is_empty() || !seen.insert(normalized.clone()) {
                None
            } else {
                Some(normalized)
            }
        })
        .collect()
}

fn alert_process_matches_name(process: &AlertProcessPivot, process_name: &str) -> bool {
    let target = normalized_process_token(process_name);
    if target.is_empty() {
        return false;
    }
    [
        process.display_name.as_str(),
        process.name.as_str(),
        process.exe_path.as_deref().unwrap_or(""),
        process.cmd_line.as_deref().unwrap_or(""),
    ]
    .iter()
    .map(|value| normalized_process_token(value))
    .any(|candidate| !candidate.is_empty() && candidate == target)
}

fn resolve_alert_process_pivots(
    process_names: &[String],
    catalog: &[AlertProcessPivot],
    alert_hostname: &str,
) -> Vec<AlertProcessPivot> {
    let mut matched = catalog
        .iter()
        .filter(|process| host_matches_local(&process.hostname, alert_hostname))
        .filter(|process| {
            process_names
                .iter()
                .any(|process_name| alert_process_matches_name(process, process_name))
        })
        .cloned()
        .collect::<Vec<_>>();
    matched.sort_by(|left, right| {
        right
            .cpu_percent
            .unwrap_or(0.0)
            .partial_cmp(&left.cpu_percent.unwrap_or(0.0))
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| {
                right
                    .mem_percent
                    .unwrap_or(0.0)
                    .partial_cmp(&left.mem_percent.unwrap_or(0.0))
                    .unwrap_or(std::cmp::Ordering::Equal)
            })
            .then_with(|| left.display_name.cmp(&right.display_name))
    });
    matched.dedup_by_key(|process| process.pid);
    matched.truncate(4);
    matched
}

#[cfg(target_os = "macos")]
fn live_alert_process_catalog(local_hostname: &str) -> Vec<AlertProcessPivot> {
    crate::collector_macos::collect_processes()
        .into_iter()
        .map(|process| {
            let name = process.name;
            let display_name = process_basename(&name).to_string();
            let exe_path = if name.contains('/') {
                Some(name.clone())
            } else {
                None
            };
            AlertProcessPivot {
                pid: process.pid,
                ppid: Some(process.ppid),
                name,
                display_name,
                user: Some(process.user),
                group: Some(process.group),
                cpu_percent: Some(process.cpu_percent),
                mem_percent: Some(process.mem_percent),
                hostname: local_hostname.to_string(),
                platform: "macos".to_string(),
                cmd_line: None,
                exe_path,
            }
        })
        .collect()
}

#[cfg(target_os = "linux")]
fn live_alert_process_catalog(local_hostname: &str) -> Vec<AlertProcessPivot> {
    crate::collector_linux::collect_processes()
        .into_iter()
        .map(|process| {
            let display_name = process_basename(&process.name).to_string();
            AlertProcessPivot {
                pid: process.pid,
                ppid: Some(process.ppid),
                name: process.name,
                display_name,
                user: Some(if process.uid == 0 {
                    "root".to_string()
                } else {
                    format!("uid:{}", process.uid)
                }),
                group: Some(format!("gid:{}", process.gid)),
                cpu_percent: None,
                mem_percent: None,
                hostname: local_hostname.to_string(),
                platform: "linux".to_string(),
                cmd_line: (!process.cmd_line.is_empty()).then_some(process.cmd_line),
                exe_path: (!process.exe_path.is_empty()).then_some(process.exe_path),
            }
        })
        .collect()
}

#[cfg(not(any(target_os = "macos", target_os = "linux")))]
fn live_alert_process_catalog(_local_hostname: &str) -> Vec<AlertProcessPivot> {
    Vec::new()
}

/// Build alert process pivots for processes tracked from remote hosts via the
/// central process tree. Local-host nodes are skipped — they are already covered
/// by `live_alert_process_catalog`. Returns up to 256 alive remote nodes.
fn remote_alert_process_catalog(
    process_tree: &crate::process_tree::ProcessTree,
    local_hostname: &str,
) -> Vec<AlertProcessPivot> {
    process_tree
        .alive_processes()
        .into_iter()
        .filter(|node| !host_matches_local(&node.hostname, local_hostname))
        .take(256)
        .map(|node| {
            let display_name = process_basename(&node.name).to_string();
            AlertProcessPivot {
                pid: node.pid,
                ppid: Some(node.ppid),
                name: node.name.clone(),
                display_name,
                user: node.user.clone(),
                group: None,
                cpu_percent: None,
                mem_percent: None,
                hostname: node.hostname.clone(),
                platform: "remote".to_string(),
                cmd_line: node.cmd_line.clone(),
                exe_path: node.exe_path.clone(),
            }
        })
        .collect()
}

/// Combine the local-host live process catalog with remote process-tree pivots
/// so alerts originating on any tracked host can be resolved to a process.
fn assemble_alert_process_catalog(
    local_hostname: &str,
    process_tree: &crate::process_tree::ProcessTree,
) -> Vec<AlertProcessPivot> {
    let mut catalog = live_alert_process_catalog(local_hostname);
    catalog.extend(remote_alert_process_catalog(process_tree, local_hostname));
    catalog
}

fn alert_process_resolution(
    alert_hostname: &str,
    local_hostname: &str,
    process_names: &[String],
    process_candidates: &[AlertProcessPivot],
) -> &'static str {
    if process_names.is_empty() {
        "none"
    } else if process_candidates.len() == 1 {
        "unique"
    } else if process_candidates.len() > 1 {
        "multiple"
    } else if !host_matches_local(alert_hostname, local_hostname) {
        "remote_host"
    } else {
        "unresolved"
    }
}

fn recent_alerts_json(
    alerts: &[AlertRecord],
    limit: usize,
    offset: usize,
    local_hostname: &str,
    process_tree: &crate::process_tree::ProcessTree,
) -> Result<String, String> {
    let capped_limit = limit.min(1000);
    let process_catalog = assemble_alert_process_catalog(local_hostname, process_tree);
    let recent: Vec<_> = alerts
        .iter()
        .enumerate()
        .rev()
        .skip(offset)
        .take(capped_limit)
        .map(|(i, a)| alert_json_value(a, i, local_hostname, &process_catalog))
        .collect();
    serde_json::to_string(&recent).map_err(|e| format!("serialization error: {e}"))
}

fn alert_json_value(
    alert: &AlertRecord,
    index: usize,
    local_hostname: &str,
    process_catalog: &[AlertProcessPivot],
) -> serde_json::Value {
    let mut obj = serde_json::to_value(alert).unwrap_or_default();
    let entities = crate::entity_extract::extract_entities(&alert.reasons);
    let process_names = extract_alert_process_names(&entities);
    let process_candidates =
        resolve_alert_process_pivots(&process_names, process_catalog, &alert.hostname);
    if let Some(map) = obj.as_object_mut() {
        map.insert("id".to_string(), serde_json::json!(index));
        map.insert("_index".to_string(), serde_json::json!(index));
        map.insert(
            "entities".to_string(),
            serde_json::to_value(&entities).unwrap_or_else(|_| serde_json::json!([])),
        );
        map.insert(
            "process_resolution".to_string(),
            serde_json::json!(alert_process_resolution(
                &alert.hostname,
                local_hostname,
                &process_names,
                &process_candidates,
            )),
        );
        if !process_names.is_empty() {
            map.insert(
                "process_names".to_string(),
                serde_json::json!(process_names),
            );
        }
        if !process_candidates.is_empty() {
            map.insert(
                "process_candidates".to_string(),
                serde_json::to_value(&process_candidates).unwrap_or_else(|_| serde_json::json!([])),
            );
            if process_candidates.len() == 1 {
                map.insert(
                    "process".to_string(),
                    serde_json::to_value(&process_candidates[0])
                        .unwrap_or_else(|_| serde_json::json!({})),
                );
            }
        }
    }
    obj
}

fn incidents_json(
    incident_store: &IncidentStore,
    query: &HashMap<String, String>,
) -> Result<String, String> {
    let status = query.get("status").map(|value| value.as_str());
    let severity = query.get("severity").map(|value| value.as_str());
    let offset = query
        .get("offset")
        .and_then(|value| value.parse::<usize>().ok())
        .unwrap_or(0);
    let limit = query
        .get("limit")
        .and_then(|value| value.parse::<usize>().ok())
        .unwrap_or(100)
        .min(1000);

    let incidents = incident_store.list_filtered(status, severity);
    let paged: Vec<_> = incidents.into_iter().skip(offset).take(limit).collect();
    serde_json::to_string(&paged).map_err(|e| format!("serialization error: {e}"))
}

fn prometheus_metrics_payload(state: &AppState) -> String {
    let agents = state.agent_registry.list();
    let heartbeat_interval = state.agent_registry.heartbeat_interval();
    let total_agents = agents.len();
    let online_agents = agents
        .iter()
        .filter(|agent| computed_agent_status(agent, heartbeat_interval).0 == "online")
        .count();
    let pending_deployments = state
        .remote_deployments
        .values()
        .filter(|deployment| deployment_is_pending(deployment, &state.agent_registry))
        .count();

    let metrics = [
        ("wardex_up", "gauge", 1_u64),
        ("wardex_alerts_total", "gauge", state.alerts.len() as u64),
        (
            "wardex_events_total",
            "gauge",
            state.event_store.count() as u64,
        ),
        ("wardex_agents_total", "gauge", total_agents as u64),
        ("wardex_agents_online", "gauge", online_agents as u64),
        (
            "wardex_incidents_total",
            "gauge",
            state.incident_store.list().len() as u64,
        ),
        (
            "wardex_cases_total",
            "gauge",
            state.case_store.list().len() as u64,
        ),
        (
            "wardex_reports_total",
            "gauge",
            state.report_store.list().len() as u64,
        ),
        (
            "wardex_response_requests_total",
            "gauge",
            state.response_orchestrator.all_requests().len() as u64,
        ),
        (
            "wardex_response_pending_total",
            "gauge",
            state.response_orchestrator.pending_requests().len() as u64,
        ),
        (
            "wardex_deployments_pending_total",
            "gauge",
            pending_deployments as u64,
        ),
        ("wardex_requests_total", "counter", state.request_count),
        ("wardex_request_errors_total", "counter", state.error_count),
        (
            "wardex_uptime_seconds",
            "gauge",
            state.server_start.elapsed().as_secs(),
        ),
    ];

    let mut body = String::new();
    for (name, metric_type, value) in metrics {
        body.push_str("# HELP ");
        body.push_str(name);
        body.push('\n');
        body.push_str("# TYPE ");
        body.push_str(name);
        body.push(' ');
        body.push_str(metric_type);
        body.push('\n');
        body.push_str(name);
        body.push(' ');
        body.push_str(&value.to_string());
        body.push('\n');
    }
    body
}

fn respond_api(
    state: &Arc<Mutex<AppState>>,
    method: &Method,
    url: &str,
    remote_addr: &str,
    auth_used: bool,
    response: Response<Body>,
) -> Response<Body> {
    let request_id = generate_request_id().unwrap_or_else(|_| {
        let random_suffix = rand::random::<u64>();
        format!("req-fallback-{random_suffix:016x}")
    });
    let status_code = response.status().as_u16();
    {
        let mut s = state.lock().unwrap_or_else(|e| e.into_inner());
        if status_code >= 400 {
            s.error_count += 1;
        }
        s.audit_log
            .record(method.as_str(), url, remote_addr, status_code, auth_used);
    }
    let (mut parts, body) = response.into_parts();
    if let Ok(hv) = request_id.parse() {
        parts.headers.insert("X-Request-Id", hv);
    }
    Response::from_parts(parts, body)
}

#[derive(Debug, Clone)]
enum AuthIdentity {
    None,
    AdminToken,
    UserToken(User),
    SessionToken { user: User, groups: Vec<String> },
}

impl AuthIdentity {
    fn is_authenticated(&self) -> bool {
        !matches!(self, AuthIdentity::None)
    }

    fn is_admin(&self) -> bool {
        matches!(self, AuthIdentity::AdminToken)
    }

    fn actor(&self) -> &str {
        match self {
            AuthIdentity::None => "anonymous",
            AuthIdentity::AdminToken => "admin",
            AuthIdentity::UserToken(user) | AuthIdentity::SessionToken { user, .. } => {
                &user.username
            }
        }
    }

    fn user(&self) -> Option<&User> {
        match self {
            AuthIdentity::UserToken(user) | AuthIdentity::SessionToken { user, .. } => Some(user),
            _ => None,
        }
    }

    fn groups(&self) -> &[String] {
        match self {
            AuthIdentity::SessionToken { groups, .. } => groups,
            _ => &[],
        }
    }
}

fn bearer_token(headers: &HeaderMap) -> Option<String> {
    if let Some(val) = headers.get("authorization")
        && let Ok(s) = val.to_str()
        && let Some((scheme, token)) = s.split_once(char::is_whitespace)
        && scheme.eq_ignore_ascii_case("bearer")
    {
        let trimmed = token.trim();
        if !trimmed.is_empty() {
            return Some(trimmed.to_string());
        }
    }
    None
}

fn secure_token_eq(provided: Option<&str>, expected: &str) -> bool {
    let Some(provided) = provided else {
        return false;
    };
    let a = provided.as_bytes();
    let b = expected.as_bytes();
    if a.len() != b.len() {
        return false;
    }
    let mut diff = 0u8;
    for (x, y) in a.iter().zip(b.iter()) {
        diff |= x ^ y;
    }
    diff == 0
}

fn cluster_peer_auth_header(state: &AppState) -> String {
    let token = state
        .config
        .cluster
        .auth_token
        .clone()
        .unwrap_or_else(|| state.token.clone());
    format!("Bearer {token}")
}

fn cluster_request_authorized(headers: &HeaderMap, state: &Arc<Mutex<AppState>>) -> bool {
    let provided = bearer_token(headers);
    let s = state.lock().unwrap_or_else(|e| e.into_inner());
    if let Some(cluster_token) = s.config.cluster.auth_token.as_deref() {
        return secure_token_eq(provided.as_deref(), cluster_token);
    }
    secure_token_eq(provided.as_deref(), &s.token)
}

fn cluster_peer_url(addr: &str, path: &str) -> String {
    let trimmed = addr.trim().trim_end_matches('/');
    if trimmed.starts_with("http://") || trimmed.starts_with("https://") {
        format!("{trimmed}{path}")
    } else {
        format!("http://{trimmed}{path}")
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ApiRouteAccess {
    Public,
    Agent,
    Cluster,
    Authenticated,
}

impl ApiRouteAccess {
    pub fn as_str(self) -> &'static str {
        match self {
            Self::Public => "public",
            Self::Agent => "agent",
            Self::Cluster => "cluster",
            Self::Authenticated => "authenticated",
        }
    }

    pub fn requires_bearer_auth(self) -> bool {
        !matches!(self, Self::Public)
    }
}

const SESSION_COOKIE_NAME: &str = "wardex_session";

fn session_cookie_token(headers: &HeaderMap) -> Option<String> {
    let cookie_header = headers.get(COOKIE)?.to_str().ok()?;
    for cookie in cookie_header.split(';') {
        let trimmed = cookie.trim();
        let Some((name, value)) = trimmed.split_once('=') else {
            continue;
        };
        if name.trim() == SESSION_COOKIE_NAME {
            let decoded = decode_query_component(value.trim().trim_matches('"'));
            if !decoded.is_empty() {
                return Some(decoded);
            }
        }
    }
    None
}

