    serde_json::json!({
        "provider": "m365_saas",
        "success": true,
        "event_count": sample_events.len(),
        "sample_events": sample_events,
        "summary": {
            "tenant_id": tenant_id,
            "client_id": client_id,
            "content_types": setup.content_types,
            "recommended_pivots": ["soc", "ueba", "assistant"],
        },
        "validation": validation,
        "error": serde_json::Value::Null,
    })
